"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import { CtrCliff, ctrAt } from "@/components/charts/CtrCliff";
import {
  KEYWORDS,
  MAX_KW_REV,
  VERDICT_NAME,
  keywordsMetrics,
  keywordCategories,
  keywordsAI,
  type KeywordRow,
} from "@/features/growth/api/growth-keywords-data";
import "./keywords.css";

const PERIOD_LABELS = ["Last 7 days", "Last 30 days", "Last 90 days"];

const fmtVol = (v: number) =>
  v >= 1000 ? `${(v / 1000).toFixed(v % 1000 === 0 ? 0 : 1)}K` : String(v);
const fmtClicks = (c: number) =>
  c >= 1000 ? `${(c / 1000).toFixed(1)}K` : String(Math.round(c));
const num = (s: string) => {
  if (!s) return 0;
  const m = s.replace(/[,$#]/g, "").match(/-?\d+(?:\.\d+)?/);
  if (!m) return 0;
  let v = parseFloat(m[0]);
  if (/k/i.test(s)) v *= 1000;
  if (/m/i.test(s)) v *= 1_000_000;
  return v;
};

type TableKey = "kw" | "pos" | "intent" | "vol" | "clicks" | "ctr" | "kd" | "rev" | "t3";

export default function KeywordsPage() {
  const [periodIdx, setPeriodIdx] = useState(1);
  const [selected, setSelected] = useState<number | null>(null);
  const [sortKey, setSortKey] = useState<TableKey>("rev");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);
  const [search, setSearch] = useState("");
  const { openBridge } = useBridge();

  const tableRows = useMemo(() => {
    const arr = KEYWORDS.filter((k) =>
      search ? k.kw.toLowerCase().includes(search.toLowerCase()) : true,
    );
    arr.sort((a, b) => {
      if (sortKey === "kw") return sortDir * a.kw.localeCompare(b.kw);
      if (sortKey === "pos") return sortDir * (a.pos - b.pos);
      if (sortKey === "intent") return sortDir * a.intent.localeCompare(b.intent);
      if (sortKey === "vol") return sortDir * (a.vol - b.vol);
      if (sortKey === "kd") return sortDir * (a.kd - b.kd);
      if (sortKey === "rev") return sortDir * (a.rev - b.rev);
      if (sortKey === "clicks") return sortDir * (a.vol * ctrAt(a.pos) - b.vol * ctrAt(b.pos));
      if (sortKey === "ctr") return sortDir * (ctrAt(a.pos) - ctrAt(b.pos));
      if (sortKey === "t3") {
        const t3a = num(a.up);
        const t3b = num(b.up);
        return sortDir * (t3a - t3b);
      }
      return 0;
    });
    return arr;
  }, [sortKey, sortDir, search]);

  const onSort = (k: TableKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "kw" || k === "intent" || k === "pos" ? 1 : -1);
    }
  };
  const th = (k: TableKey, label: string, n = false) => {
    const active = sortKey === k;
    return (
      <th className={`${n ? "num " : ""}${active ? "active" : ""}`} onClick={() => onSort(k)}>
        {label}
        <span className="sort-ar">{active && sortDir < 0 ? "↓" : "↑"}</span>
      </th>
    );
  };

  return (
    <div className="growth-keywords-page">
      <DeptHeader
        dept="growth"
        title="Keywords"
        meta={
          <>
            <span className="live">Live</span> · Where you rank · what each position earns · from Search Console
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("growth")}
            >
              Improve top keyword →
            </button>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} accent="var(--d-growth)" />

      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Keyword revenue</div>
          <div className="metric-v green">{keywordsMetrics.revenue}</div>
          <div className="metric-s">{keywordsMetrics.revenueSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">One move away</div>
          <div className="metric-v compass">{keywordsMetrics.oneMove}</div>
          <div className="metric-s">{keywordsMetrics.oneMoveSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Strike distance</div>
          <div className="metric-v">{keywordsMetrics.strike}</div>
          <div className="metric-s">{keywordsMetrics.strikeSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Avg position</div>
          <div className="metric-v">{keywordsMetrics.avgPos}</div>
          <div className="metric-s">{keywordsMetrics.avgPosSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Declining</div>
          <div className="metric-v amber">{keywordsMetrics.declining}</div>
          <div className="metric-s">{keywordsMetrics.decliningSub}</div>
        </div>
      </div>

      <AIStrip label={keywordsAI.label} meta={keywordsAI.meta} cards={keywordsAI.cards} />

      {/* Master / detail */}
      <SectionLabel>Every keyword, ranked by what it earns — select to see the position gap</SectionLabel>
      <div className={`kw-split${selected !== null ? " open" : ""}`}>
        <div className="kw-main">
          <div className="kw-list">
            {KEYWORDS.map((k, i) => (
              <KwRowEl
                key={k.kw}
                k={k}
                selected={selected === i}
                onSelect={() => setSelected((cur) => (cur === i ? null : i))}
              />
            ))}
          </div>
        </div>
        <aside className="kw-detail-aside">
          {selected !== null && (
            <KwDetail
              k={KEYWORDS[selected]}
              onClose={() => setSelected(null)}
              openBridge={() => openBridge("growth")}
            />
          )}
        </aside>
      </div>

      {/* Category cards */}
      <SectionLabel>All keywords</SectionLabel>
      <div className="kw-cats">
        {keywordCategories.map((c) => (
          <div
            key={c.id}
            className="kw-cat"
            style={{ ["--cat" as string]: c.color } as React.CSSProperties}
          >
            <div className="kw-cat-title">{c.name}</div>
            <div className="kw-cat-sub">{c.sub}</div>
            <div className="kw-cat-row">
              <div className="kw-cat-num">
                {c.count}
                <small>keywords</small>
              </div>
              <div className="kw-cat-money">
                <div className="v">{c.money}</div>
                <div className="p">{c.note}</div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Tools + table */}
      <div className="kw-tools">
        <div className="pt-search">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="11" cy="11" r="7" />
            <line x1="21" y1="21" x2="16.5" y2="16.5" />
          </svg>
          <input
            type="text"
            placeholder="Search keywords…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="kw-filters">
          <button className="kw-filter" type="button">
            All intents
            <svg viewBox="0 0 10 10" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M2 4 L5 7 L8 4" />
            </svg>
          </button>
          <button className="kw-filter" type="button">
            All tiers
            <svg viewBox="0 0 10 10" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M2 4 L5 7 L8 4" />
            </svg>
          </button>
        </div>
      </div>
      <div className="kw-table-wrap">
        <table className="kw-table">
          <thead>
            <tr>
              {th("kw", "Keyword")}
              {th("pos", "Position")}
              {th("intent", "Intent")}
              {th("vol", "Volume", true)}
              {th("clicks", "Clicks", true)}
              {th("ctr", "CTR", true)}
              {th("kd", "KD", true)}
              {th("rev", "Revenue", true)}
              {th("t3", "If top 3", true)}
            </tr>
          </thead>
          <tbody>
            {tableRows.map((k) => {
              const clicksNow = k.vol * ctrAt(k.pos) / 100;
              return (
                <tr key={k.kw}>
                  <td>{k.kw}</td>
                  <td>#{k.pos}</td>
                  <td>{k.intent}</td>
                  <td className="num">{fmtVol(k.vol)}</td>
                  <td className="num">{fmtClicks(clicksNow)}</td>
                  <td className="num">{ctrAt(k.pos).toFixed(1)}%</td>
                  <td className="num">{k.kd}</td>
                  <td className="num">{k.revStr}</td>
                  <td className="num">{k.up}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function KwRowEl({
  k,
  selected,
  onSelect,
}: {
  k: KeywordRow;
  selected: boolean;
  onSelect: () => void;
}) {
  const w = Math.max(3, Math.round((k.rev / MAX_KW_REV) * 100));
  const mvCls = k.move > 0 ? "up" : k.move < 0 ? "down" : "flat";
  const mvTxt = k.move > 0 ? `↑${k.move}` : k.move < 0 ? `↓${Math.abs(k.move)}` : "—";
  const meta =
    k.flag === "trap"
      ? `vol ${fmtVol(k.vol)} · intent ${k.buyerIntent}%`
      : `${ctrAt(k.pos).toFixed(1)}% CTR · vol ${fmtVol(k.vol)}`;
  return (
    <div
      className={`kw-row f-${k.flag}${selected ? " sel" : ""}`}
      onClick={onSelect}
    >
      <div className="kw-pos">
        <div className="p"><span className="h">#</span>{k.pos}</div>
        <div className={`mv ${mvCls}`}>{mvTxt}</div>
      </div>
      <div className="kw-main-block">
        <div className="kw-name">
          {k.kw}
          <span className={`vd ${k.flag}`}>{VERDICT_NAME[k.flag]}</span>
        </div>
        <div className="kw-barrow">
          <div className="kw-bar">
            <div className={`kw-bar-fill ${k.flag}`} style={{ width: `${w}%` }} />
          </div>
          <div className="kw-meta">
            {meta}
            {k.aio && <span className="aio-chip">AI Overview</span>}
          </div>
        </div>
      </div>
      <div className="kw-money">
        <div className={`m${k.flag === "trap" ? " muted" : ""}`}>{k.revStr}</div>
        <div className="u">/mo earned</div>
        <div className={`up ${k.flag}`}>{k.up}</div>
      </div>
    </div>
  );
}

function KwDetail({
  k,
  onClose,
  openBridge,
}: {
  k: KeywordRow;
  onClose: () => void;
  openBridge: () => void;
}) {
  const kicker: Record<typeof k.flag, string> = {
    champ: k.mode === "climb" ? "Champion · headroom to #1" : "Champion · defend the position",
    strike: "Strike distance · one move from top 3",
    decl: "Declining · the slide is the alarm",
    trap: "Trap · skip on purpose",
  };

  // Money block — climb shows before→after, others show just current
  const upMatch = k.up.match(/-?\d+(?:\.\d+)?/);
  const upRaw = upMatch ? parseFloat(upMatch[0]) : 0;
  const upMult = /K/.test(k.up) ? 1000 : 1;
  const upSigned = (k.up.startsWith("−") ? -1 : 1) * upRaw * upMult;
  const after = k.rev + upSigned;
  const moneyStr = (n: number) => `$${Math.round(n / 1000)}K`;

  const cNow = (k.vol * ctrAt(k.pos)) / 100;
  let trio: React.ReactNode = null;
  if (k.mode === "climb" && k.target !== undefined) {
    const cT = (k.vol * ctrAt(k.target)) / 100;
    trio = (
      <>
        <Stat v={`#${k.pos}`} l="current position" />
        <Stat v={Math.round(cNow).toLocaleString()} l="clicks /mo now" />
        <Stat v={Math.round(cT).toLocaleString()} l={`clicks /mo at #${k.target}`} tone="green" />
      </>
    );
  } else if (k.mode === "defend" && k.riskPos !== undefined) {
    const cR = (k.vol * ctrAt(k.riskPos)) / 100;
    trio = (
      <>
        <Stat v={`#${k.pos}`} l="holding" />
        <Stat v={Math.round(cNow).toLocaleString()} l="clicks /mo now" tone="green" />
        <Stat v={Math.round(cR).toLocaleString()} l={`clicks if #${k.riskPos}`} tone="red" />
      </>
    );
  } else if (k.mode === "slip" && k.was !== undefined) {
    const cWas = (k.vol * ctrAt(k.was)) / 100;
    trio = (
      <>
        <Stat v={`#${k.was}→#${k.pos}`} l="position" tone="red" />
        <Stat v={Math.round(cWas).toLocaleString()} l="clicks /mo before" />
        <Stat v={Math.round(cNow).toLocaleString()} l="clicks /mo now" tone="red" />
      </>
    );
  } else {
    trio = (
      <>
        <Stat v={`#${k.pos}`} l="ranks here" />
        <Stat v={`${k.buyerIntent}%`} l="buyer intent" tone="red" />
        <Stat v={k.revStr} l="/mo earned" />
      </>
    );
  }

  // SERP ladder rows
  const rungs: React.ReactNode[] = [];
  for (let p = 1; p <= 3; p++) {
    const who = k.serp[p - 1];
    const isYou = who === "YOU";
    const share = Math.round((ctrAt(p) / ctrAt(1)) * 100);
    rungs.push(
      <div key={`rung-${p}`} className={`rung${isYou ? " you" : ""}`}>
        <div className="rp">#{p}</div>
        <div className="rd">
          {isYou ? (
            <>
              Your page <span className="tag">YOU</span>
            </>
          ) : (
            who
          )}
        </div>
        <div className="rbar">
          <i style={{ width: `${Math.max(6, share)}%` }} />
        </div>
      </div>,
    );
  }
  if (k.pos > 3) {
    const share = Math.round((ctrAt(k.pos) / ctrAt(1)) * 100);
    rungs.push(
      <div key="dots" className="rung gap">
        <div className="dots">···</div>
      </div>,
    );
    rungs.push(
      <div key="you-rung" className="rung you">
        <div className="rp">#{k.pos}</div>
        <div className="rd">
          Your page <span className="tag">YOU</span>
        </div>
        <div className="rbar">
          <i style={{ width: `${Math.max(6, share)}%` }} />
        </div>
      </div>,
    );
  }

  return (
    <div className="kw-detail">
      <button className="kd-clear" aria-label="Close" type="button" onClick={onClose}>✕</button>
      <div className={`kd-kicker ${k.flag}`}>
        <span className="kdot" />
        {kicker[k.flag]}
      </div>
      <div className="kd-name">{k.kw}</div>
      <div className="kd-page">
        {k.page} · {fmtVol(k.vol)} searches/mo
      </div>

      {k.mode === "climb" ? (
        <div className="kd-money">
          <span className="big">{k.revStr}</span>
          <span className="arr">→</span>
          <span className="big green">{moneyStr(after)}</span>
          <span className="per">/mo</span>
        </div>
      ) : k.mode === "defend" ? (
        <div className="kd-money">
          <span className="big green">{k.revStr}</span>
          <span className="per">/mo</span>
        </div>
      ) : k.mode === "slip" ? (
        <div className="kd-money">
          <span className="big">{k.revStr}</span>
          <span className="per">/mo</span>
        </div>
      ) : (
        <div className="kd-money">
          <span className="big muted">{k.revStr}</span>
          <span className="per">/mo</span>
        </div>
      )}

      <div className="kd-money-sub">
        {k.sub[0]}
        <span className={`em ${k.sub[1]}`}>{k.up}</span>
      </div>

      <CtrCliff
        data={{
          pos: k.pos,
          flag: k.flag,
          mode: k.mode,
          target: k.target,
          riskPos: k.riskPos,
          was: k.was,
          buyerIntent: k.buyerIntent,
          intent: k.intent,
        }}
      />

      <div className="kd-stats" style={{ marginTop: 18 }}>
        {trio}
      </div>

      <div className="kd-ladder-title">Top of the SERP</div>
      <div className="ladder">{rungs}</div>

      <div className="kd-line">{k.line}</div>

      <div className="kd-actions">
        <span className="eff">
          KD {k.kd} · {k.intent} · {k.page}
        </span>
        {k.flag === "trap" ? (
          <button className="btn-util" type="button">Mark reviewed</button>
        ) : k.flag === "champ" ? (
          <>
            <button className="btn-util" type="button">Set defend alert</button>
            <button className="btn-util primary" type="button" onClick={openBridge}>
              Open in Bridge →
            </button>
          </>
        ) : (
          <>
            <button className="btn-util" type="button">Dismiss</button>
            <button className="btn-util primary" type="button" onClick={openBridge}>
              {k.flag === "decl" ? "Defend in Bridge →" : "Improve in Bridge →"}
            </button>
          </>
        )}
      </div>
    </div>
  );
}

function Stat({
  v,
  l,
  tone,
}: {
  v: React.ReactNode;
  l: string;
  tone?: "green" | "red";
}) {
  return (
    <div className="kd-stat">
      <div className={`v${tone ? " " + tone : ""}`}>{v}</div>
      <div className="l">{l}</div>
    </div>
  );
}
