"use client";

/* ════════════════════════════════════════════════════════════════════════
   <CtrCliff> — the Tier-1 SEO instrument per CHART-STANDARD §5.

   Question it answers: what does a rank drop cost?
   Instrument form: smooth curve of organic CTR by SERP position 1→10
   with you-vs-target markers and a now-beacon at your position.

   Four interaction modes:
     - "climb"  → green filled wedge from current pos → target, with TARGET
                  marker at the higher CTR
     - "defend" → red shaded wedge from current pos → risk pos (e.g. "if #6")
     - "slip"   → red dashed arrow from WAS pos down to NOW pos
     - "trap"   → grey marker + buyer-intent caveat line

   Conforms to §2 (real-px viewBox via useChartSize, no preserveAspectRatio="none",
   tokens not hex except inside hand-stamped color helpers, four states via
   <ChartStates>). Reduced motion stops the now-beacon pulse.
   ──────────────────────────────────────────────────────────────────────── */

import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export type CtrCliffMode = "climb" | "defend" | "slip" | "trap";
export type CtrCliffFlag = "champ" | "strike" | "decl" | "trap";

export interface CtrCliffPoint {
  /** Current SERP position (1+). */
  pos: number;
  /** "champ" / "strike" / "decl" / "trap" — drives the verdict color. */
  flag: CtrCliffFlag;
  mode: CtrCliffMode;
  /** Required for "climb": where we're aiming. */
  target?: number;
  /** Required for "defend": where the rank could slip to. */
  riskPos?: number;
  /** Required for "slip": where the keyword used to be. */
  was?: number;
  /** Required for "trap": approximate buyer-intent %. */
  buyerIntent?: number;
  /** "BUY" / "COMM" / "INFO" — shown under the trap marker. */
  intent?: string;
}

export interface CtrCliffProps {
  data?: CtrCliffPoint;
  state?: ChartState;
  label?: string;
}

/** Organic CTR by SERP position — derived from real-world averages. */
const CTR_BY_POS: Record<number, number> = {
  1: 31,
  2: 16,
  3: 11,
  4: 8,
  5: 6,
  6: 4.6,
  7: 3.6,
  8: 3.0,
  9: 2.5,
  10: 2.2,
};

export const sampleCtrCliffData: CtrCliffPoint = {
  pos: 6,
  flag: "strike",
  mode: "climb",
  target: 3,
};

export function ctrAt(p: number): number {
  if (p <= 10) return CTR_BY_POS[p] ?? CTR_BY_POS[10];
  return Math.round(Math.max(0.6, 2.2 - (p - 10) * 0.12) * 10) / 10;
}

function verdictColor(f: CtrCliffFlag): string {
  switch (f) {
    case "champ": return "#1D9E75";
    case "strike": return "#5B7CB0";
    case "decl": return "#d64545";
    case "trap": return "#b0aca2";
    default: return "#5B7CB0";
  }
}

/** Catmull-Rom-ish smoothing for the cliff path. */
function smoothPath(pts: [number, number][]): string {
  if (pts.length < 2) return "";
  let d = `M ${pts[0][0].toFixed(1)} ${pts[0][1].toFixed(1)}`;
  for (let i = 0; i < pts.length - 1; i++) {
    const p0 = pts[i - 1] ?? pts[i];
    const p1 = pts[i];
    const p2 = pts[i + 1];
    const p3 = pts[i + 2] ?? p2;
    const c1x = p1[0] + (p2[0] - p0[0]) / 6;
    const c1y = p1[1] + (p2[1] - p0[1]) / 6;
    const c2x = p2[0] - (p3[0] - p1[0]) / 6;
    const c2y = p2[1] - (p3[1] - p1[1]) / 6;
    d += ` C ${c1x.toFixed(1)} ${c1y.toFixed(1)} ${c2x.toFixed(1)} ${c2y.toFixed(1)} ${p2[0].toFixed(1)} ${p2[1].toFixed(1)}`;
  }
  return d;
}

export function CtrCliff({
  data = sampleCtrCliffData,
  state = "ready",
  label = "CTR cliff",
}: CtrCliffProps) {
  const { ref, width } = useChartSize({ min: 480, fallback: 520 });
  const reduce = usePrefersReducedMotion();

  const W = Math.max(480, width);
  const H = 300;
  const padL = 50;
  const padR = 26;
  const padT = 28;
  const padB = 48;
  const plotW = W - padL - padR;
  const plotH = H - padT - padB;
  const base = padT + plotH;
  const maxC = 33;

  const X = (p: number) => padL + ((Math.min(p, 10) - 1) / 9) * plotW;
  const Y = (c: number) => padT + (1 - c / maxC) * plotH;

  const pts: [number, number][] = [];
  for (let p = 1; p <= 10; p++) pts.push([X(p), Y(CTR_BY_POS[p])]);
  const line = smoothPath(pts);
  const area = line + ` L ${pts[9][0]} ${base} L ${pts[0][0]} ${base} Z`;

  const v = verdictColor(data.flag);
  const youX = X(data.pos);
  const youY = Y(ctrAt(data.pos));

  // Wedge helper — filled polygon between two positions along the cliff
  const wedge = (fromP: number, toP: number, fill: string): string => {
    const a = Math.min(fromP, toP);
    const b = Math.max(fromP, toP);
    let d = `M ${X(a)} ${base}`;
    for (let p = a; p <= b; p++) d += ` L ${X(p).toFixed(1)} ${Y(CTR_BY_POS[p]).toFixed(1)}`;
    d += ` L ${X(b)} ${base} Z`;
    return `<path d="${d}" fill="${fill}"/>`;
  };

  const guide = (x: number, y: number, color: string) => (
    <>
      <line x1={padL} y1={y} x2={x} y2={y} stroke={color} strokeWidth={1} strokeDasharray="3 3" opacity={0.5} />
      <line x1={x} y1={y} x2={x} y2={base} stroke={color} strokeWidth={1} strokeDasharray="3 3" opacity={0.5} />
    </>
  );
  const flag = (y: number, txt: string, color: string) => (
    <>
      <rect x={padL - 44} y={y - 10} width={40} height={20} rx={3} fill={color} />
      <text x={padL - 24} y={y + 4} fontSize={11} fontWeight={600} fill="#fff" textAnchor="middle">
        {txt}
      </text>
    </>
  );
  const plab = (x: number, role: string, color: string) => (
    <text
      x={x}
      y={base + 35}
      fontSize={10.5}
      fontWeight={600}
      letterSpacing="0.05em"
      fill={color}
      textAnchor="middle"
    >
      {role}
    </text>
  );
  const dotFilled = (x: number, y: number, color: string) => (
    <>
      <circle cx={x} cy={y} r={7} fill={color} />
      <circle cx={x} cy={y} r={2.8} fill="#fff" />
    </>
  );
  const dotRing = (x: number, y: number, color: string) => (
    <circle cx={x} cy={y} r={6.5} fill="#fff" stroke={color} strokeWidth={2.4} />
  );
  /** Now-beacon — two staggered rings pulsing out behind the YOU marker. */
  const pulse = (x: number, y: number, color: string) =>
    reduce ? null : (
      <>
        <circle cx={x} cy={y} r={6} fill="none" stroke={color} strokeWidth={1.8}>
          <animate attributeName="r" values="6;20" dur="2.2s" repeatCount="indefinite" />
          <animate attributeName="opacity" values="0.5;0" dur="2.2s" repeatCount="indefinite" />
        </circle>
        <circle cx={x} cy={y} r={6} fill="none" stroke={color} strokeWidth={1.8}>
          <animate attributeName="r" values="6;20" dur="2.2s" begin="1.1s" repeatCount="indefinite" />
          <animate attributeName="opacity" values="0.5;0" dur="2.2s" begin="1.1s" repeatCount="indefinite" />
        </circle>
      </>
    );

  /* ── Mode-specific overlay ── */
  let modeOverlay: React.ReactNode = null;
  if (data.mode === "climb" && data.target !== undefined) {
    const tX = X(data.target);
    const tY = Y(CTR_BY_POS[data.target]);
    modeOverlay = (
      <>
        <g dangerouslySetInnerHTML={{ __html: wedge(data.target, data.pos, "rgba(29,158,117,0.16)") }} />
        {guide(tX, tY, "#1D9E75")}
        {guide(youX, youY, v)}
        {dotRing(tX, tY, "#1D9E75")}
        {pulse(youX, youY, v)}
        {dotFilled(youX, youY, v)}
        {flag(tY, `${CTR_BY_POS[data.target]}%`, "#1D9E75")}
        {flag(youY, `${ctrAt(data.pos)}%`, v)}
        {plab(tX, `TARGET #${data.target}`, "#1D9E75")}
        {plab(youX, `YOU #${data.pos}`, v)}
      </>
    );
  } else if (data.mode === "defend" && data.riskPos !== undefined) {
    const rX = X(data.riskPos);
    const rY = Y(CTR_BY_POS[data.riskPos]);
    modeOverlay = (
      <>
        <g dangerouslySetInnerHTML={{ __html: wedge(data.pos, data.riskPos, "rgba(214,69,69,0.13)") }} />
        {guide(rX, rY, "#d64545")}
        {guide(youX, youY, "#1D9E75")}
        {dotRing(rX, rY, "#d64545")}
        {pulse(youX, youY, "#1D9E75")}
        {dotFilled(youX, youY, "#1D9E75")}
        {flag(rY, `${CTR_BY_POS[data.riskPos]}%`, "#d64545")}
        {flag(youY, `${ctrAt(data.pos)}%`, "#1D9E75")}
        {plab(rX, `IF #${data.riskPos}`, "#d64545")}
        {plab(youX, `YOU #${data.pos}`, "#1D9E75")}
      </>
    );
  } else if (data.mode === "slip" && data.was !== undefined) {
    const wX = X(data.was);
    const wY = Y(CTR_BY_POS[data.was]);
    const ang = (Math.atan2(youY - wY, youX - wX) * 180) / Math.PI + 90;
    modeOverlay = (
      <>
        <line x1={wX} y1={wY} x2={youX} y2={youY} stroke="#d64545" strokeWidth={1.8} strokeDasharray="5 3" />
        <polygon
          points={`${youX},${youY} ${youX - 5.5},${youY - 8} ${youX + 5.5},${youY - 8}`}
          fill="#d64545"
          transform={`rotate(${ang} ${youX} ${youY})`}
        />
        {guide(youX, youY, "#d64545")}
        <circle cx={wX} cy={wY} r={6.5} fill="#fff" stroke="#d64545" strokeWidth={2} opacity={0.6} />
        {pulse(youX, youY, "#d64545")}
        {dotFilled(youX, youY, "#d64545")}
        {flag(wY, `${CTR_BY_POS[data.was]}%`, "#c98a8a")}
        {flag(youY, `${ctrAt(data.pos)}%`, "#d64545")}
        {plab(wX, `WAS #${data.was}`, "#c98a8a")}
        {plab(youX, `NOW #${data.pos}`, "#d64545")}
      </>
    );
  } else if (data.mode === "trap") {
    const biY = Y((data.buyerIntent ?? 0) * 0.06 + 0.3);
    modeOverlay = (
      <>
        {guide(youX, youY, "#9a9d9f")}
        {dotFilled(youX, youY, "#b0aca2")}
        {flag(youY, `${ctrAt(data.pos)}%`, "#9a9d9f")}
        {plab(youX, `#${data.pos} · ${data.intent ?? ""}`, "#8a8d94")}
        <line
          x1={padL}
          y1={biY}
          x2={W - padR}
          y2={biY}
          stroke="#d64545"
          strokeWidth={1.2}
          strokeDasharray="2 3"
          opacity={0.8}
        />
        <text x={padL + 4} y={biY - 7} fontSize={9.5} fill="#c0556a" textAnchor="start" fontWeight={600}>
          BUYER INTENT ~{data.buyerIntent}% — CLICKS DON&rsquo;T CONVERT
        </text>
      </>
    );
  }

  return (
    <div ref={ref} style={{ width: "100%" }}>
      <ChartStates state={state} height={H} label={label}>
        <svg className="ctr-cliff" viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: `${H}px`, display: "block" }}>
          <defs>
            <linearGradient id="ctr-cliff-grad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0" stopColor="#7F77DD" stopOpacity="0.16" />
              <stop offset="1" stopColor="#7F77DD" stopOpacity="0" />
            </linearGradient>
          </defs>

          {/* Vertical position gridlines */}
          {Array.from({ length: 10 }, (_, k) => {
            const p = k + 1;
            return (
              <line
                key={`v-${p}`}
                x1={X(p)}
                y1={padT}
                x2={X(p)}
                y2={base}
                stroke="rgba(0,0,0,0.04)"
                strokeWidth={0.5}
              />
            );
          })}
          {/* Horizontal CTR gridlines + y labels */}
          {[0, 10, 20, 30].map((c) => {
            const y = Y(c);
            return (
              <g key={`h-${c}`}>
                <line x1={padL} y1={y} x2={W - padR} y2={y} stroke="rgba(0,0,0,0.08)" strokeWidth={0.5} />
                <text x={padL - 11} y={y + 3.5} fontSize={10} fill="#8a8d94" textAnchor="end">
                  {c}%
                </text>
              </g>
            );
          })}
          {/* X position labels */}
          {Array.from({ length: 10 }, (_, k) => {
            const p = k + 1;
            return (
              <text key={`xl-${p}`} x={X(p)} y={base + 18} fontSize={10} fill="#8a8d94" textAnchor="middle">
                #{p}
              </text>
            );
          })}

          {/* Filled area + smoothed cliff curve */}
          <path d={area} fill="url(#ctr-cliff-grad)" />
          <path d={line} fill="none" stroke="#7F77DD" strokeWidth={2.4} strokeLinecap="round" strokeLinejoin="round" />

          {/* Light position dots on the curve */}
          {pts.map(([x, y], i) => (
            <circle key={`cd-${i}`} cx={x.toFixed(1)} cy={y.toFixed(1)} r={2} fill="#7F77DD" opacity={0.28} />
          ))}

          {modeOverlay}
        </svg>
      </ChartStates>
    </div>
  );
}
