/**
 * Mock data for Growth · Keywords.
 *
 * Each row pairs a keyword with its current SERP position and the verdict
 * we're shipping for it — champ / strike / decl / trap. The detail panel
 * reads each row's `mode` to render the CTR cliff in climb / defend / slip
 * / trap form, plus the SERP ladder.
 */

import type { CtrCliffFlag, CtrCliffMode } from "@/components/charts/CtrCliff";

export type KwIntent = "BUY" | "COMM" | "INFO";

export interface KeywordRow {
  kw: string;
  page: string;
  flag: CtrCliffFlag;
  mode: CtrCliffMode;
  /** Current SERP position. */
  pos: number;
  /** Net position move this period (negative = slipped). */
  move: number;
  /** Where it was last period (for slip mode). */
  was?: number;
  vol: number;
  rev: number;
  revStr: string;
  /** Pithy sentence shown next to the money figure, e.g. "+$14K if #3". */
  up: string;
  riskPos?: number;
  target?: number;
  kd: number;
  intent: KwIntent;
  /** SERP top-3 brand order, "YOU" for your own page. */
  serp: [string, string, string];
  /** [opening sentence, verdict-class string] used in the detail panel. */
  sub: [string, "champ" | "strike" | "decl" | "trap"];
  /** Italic argument line at the bottom of the detail panel. */
  line: string;
  /** Whether the keyword has an AI Overview block in the SERP. */
  aio?: boolean;
  /** Trap-only — rough buyer-intent share %. */
  buyerIntent?: number;
}

